head.script:
						var SelectedID=1;            
var g_UT;
var g_WF;
var g_MODE;
var g_DEBUG;
var g_ETTY;
var g_LABEL;
var g_CACHE=new Array();

function amp() { return String.fromCharCode(38); }
function may() { return String.fromCharCode(62); }
function men() { return String.fromCharCode(60); }
function compare(V1,V2) 
{
if (V1==V2) return 0;
return (V1-V2).toString().substr(0,1)=="-"?-1:1; 
}

function String2Number(value)   
{
value=parseFloat(value);
if (isNaN(value)) value=null;
return value;
}

function String2String(value)   
{                     
var idx;

//busco el Ampersan
idx=value.indexOf(amp());
if (idx!=-1) value=value.substr(0,idx);

//busco el Apostrofe
idx=value.indexOf("'");
if (idx!=-1) value=value.substr(0,idx);

//Resultado
if (value=="") value=null;
return value;
}                       

function String2Time(value)
{
value=parseFloat(value);
if (isNaN(value)) value=null;

var aux=new Date();
aux=new Date(aux.getFullYear(),aux.getMonth(),aux.getDate()+Math.floor(value));

return (aux.getFullYear()*10000 + aux.getMonth()*100 + 100 + aux.getDate()).toString();
}

function String2Time2(value)
{
value=parseFloat(value);
if (isNaN(value)) value=null;

var aux=new Date();
aux=new Date(aux.getFullYear(),aux.getMonth(),aux.getDate()-Math.floor(value));

return (aux.getFullYear()*10000 + aux.getMonth()*100 + 100 + aux.getDate()).toString();
}

function String2Date(cval)
{
var year, month, day;
if ( cval == "" ) return null;

if ( cval.toUpperCase() == "HOY" )
{
	Now=new Date();
	day  =Now.getDate();
	month=Now.getMonth()+1;
	year =Now.getFullYear();
} else
if ( cval.toUpperCase() == "AYER" )
{
	Now=new Date();
	Now=new Date(Now.getFullYear(),Now.getMonth(),Now.getDate()-1);
	day  =Now.getDate();
	month=Now.getMonth()+1;
	year =Now.getFullYear();
} else
if (( cval.toUpperCase() == "MA#NA" ) || ( cval.toUpperCase() == "MA#" )  || ( cval.toUpperCase() == "MANANA" ))
{
	Now=new Date();
	Now=new Date(Now.getFullYear(),Now.getMonth(),Now.getDate()+1);
	day  =Now.getDate();
	month=Now.getMonth()+1;
	year =Now.getFullYear();
} else
if (( cval.substr(0,1) == "+" ) || ( cval.substr(0,1) == "-" ))
{
	Now=new Date();
	Now=new Date(Now.getFullYear(),Now.getMonth(),Now.getDate()+parseInt(cval,10));
	day  =Now.getDate();
	month=Now.getMonth()+1;
	year =Now.getFullYear();
} else
if (cval.split("/").length==2)
{
	Now=new Date();
	day  =cval.split("/")[0];
	month=cval.split("/")[1];
	year =Now.getFullYear();
} else
if (cval.split("/").length==3)
{
	Now=new Date();
	day  =cval.split("/")[0];
	month=cval.split("/")[1];
	year =cval.split("/")[2];
} else
switch(cval.length)
{
	case 8: //ddmmyyyy
		day  =cval.substr(0,2);
		month=cval.substr(2,2);
		year =cval.substr(4,4);
	break;

	case 6: //ddmmyy
		day  =cval.substr(0,2);
		month=cval.substr(2,2);
		year =cval.substr(4,2);
	break;

	case 4: //ddmm
		Now=new Date();
		day  =cval.substr(0,2);
		month=cval.substr(2,2);
		year =Now.getFullYear();
	break;

	case 2:
	case 1:
		Now=new Date();
		day  =cval;
		month=Now.getMonth()+1;
		year =Now.getFullYear();
	break;

	default:
		return null;
}

year =parseInt(year ,10);
prevmonth=month;
month=parseInt(month,10);
day  =parseInt(day,10);

if (isNaN(year )) return null;
if (isNaN(month)) 
{
	switch(prevmonth.substr(0,3).toUpperCase())
	{
		case "ENE": month=1; break;
		case "FEB": month=2; break;
		case "MAR": month=3; break;
		case "ABR": month=4; break;
		case "MAY": month=5; break;
		case "JUN": month=6; break;
		case "JUL": month=7; break;
		case "AGO": month=8; break;
		case "SEP": month=9; break;
		case "OCT": month=10; break;
		case "NOV": month=11; break;
		case "DIC": month=12; break;
		default: return null;
	}
}

if (compare(year,50 )==-1) year+=2000;
if (compare(year,100)==-1) year+=1900;
if (compare(month,1   )==-1 || compare(month,12  )==1) return null;
if (compare(year ,1900)==-1 || compare(year ,2100)==1) return null;
if (compare(day  ,1   )==-1 || compare(day  ,31  )==1) return null;

return (year*10000 + month*100 + day).toString();
}


function ExtractValues(sType, sValue)
{
var retval=new Array();

switch(sType.toUpperCase())
{
case "FK":
case "STRING":
case "ENUM":
	retval[0]=String2String(sValue);
	break;

case "BOOL":             
	switch(sValue.toUpperCase().substr(0,1))
	{                
		case "1": //1
		case "S": //Si
		case "V": //Verdadero 
		case "T": //True 
			retval[0]=1;
			break;

		default:
			retval[0]=0;
			break;
	}
	break;

case "DATE":
	sValue=sValue.split("-");
	if (sValue.length==1)
	{
		retval[0]=String2Date(sValue[0]);
	} else
	{
		retval[0]=String2Date(sValue[0]);
		retval[1]=String2Date(sValue[1]);
	}
	break;

case "TIME":
	retval[0]=null;
	retval[1]=String2Time(sValue);
	break;

case "TIME2":
	retval[0]=null;
	retval[1]=String2Time2(sValue);
	break;

case "INT":
case "DOUBLE":	
	sValue=sValue.split("-");
	if (sValue.length==1)    
	{
		retval[0]=String2Number(sValue[0]);
	} else
	{
		retval[0]=String2Number(sValue[0]);
		retval[1]=String2Number(sValue[1]);
	}
	break;

default:
	alert("Tipo de Datos '"+sType+"' no encontrado...");
}

return retval;
}

function RefreshList()
{  
var fil, fil2, obj, objC, objF;
obj=document.getElementById("main");

fil=""; PAV="---";
for (t=1; t!=8; t++)
{   
objC=document.getElementById("C_"+t);
if (objC)
	if (objC.checked)
	{
		switch(t)
		{        
			case 1: //Vencido
				PAV="X"+PAV.substr(1,2);
				break;

			case 2: //Proximo a Vencer
				PAV=PAV.substr(0,1)+"X"+PAV.substr(2,1);
				break;

			case 3: //OK
				PAV=PAV.substr(0,2)+"X";
				break;

			case 4: //ERROR
				fil+=(fil?",":"")+"E";
				break;

			case 5: //PAUSADO      
				fil+=(fil?",":"")+"P";
				break;

			case 6: //FINALIZADO   
				fil+=(fil?",":"")+"F";
				break;

			case 7: //TERMINADO  
				fil+=(fil?",":"")+"S";
				break;
		}
	}
}

if (PAV=="XXX") 
	fil+=(fil?",":"")+"R";

fil2="";
objC=document.getElementById("filterText");
objF=document.getElementById("filterField");

if (objC)
if (objF)
if (objC.value!="")
{                
var VG=objF.value.split("-")[0];
var VT=objF.value.split("-")[1];
var VC=objF.value.split("-")[2];
var VA=ExtractValues(VT,""+objC.value);

switch(VT.toUpperCase())
{
	case 'BOOL':
		if (VG=="") 
		{
			if (VA[0]!=null) fil2="BH:"+VC+":"+VA[0].toUpperCase();
		} else 
		{
			if (VA[0]!=null) fil2="BC:"+VG+":"+VC+":"+VA[0].toUpperCase();
		}
		break;

	case 'FK':
	case 'STRING':
		if (VG=="") 
		{
			if (VA[0]!=null) fil2="SH:"+VC+":"+VA[0].toUpperCase();
		} else 
		{
			if (VA[0]!=null) fil2="SC:"+VG+":"+VC+":"+VA[0].toUpperCase();
		}
		break;                           

	case 'ENUM':   
		VALS=objF.value.split("-")[3].split(",");
		TXTS=objF.value.split("-")[4].split(",");

		FILVAL="";
		if (VA[0]!=null)
			for(t=0; t!=TXTS.length; t++)
				if (TXTS[t].toUpperCase().indexOf(VA[0].toUpperCase())!=-1)
					FILVAL+=(FILVAL==""?"":",")+VALS[t];

		if (VG=="") 
		{
			if (FILVAL!="") fil2="SH:"+VC+":"+FILVAL.toUpperCase();
		} else 
		{
			if (FILVAL!="") fil2="SC:"+VG+":"+VC+":"+FILVAL.toUpperCase();
		}
		break;                           

	case "INT":
	case "DOUBLE":	   
		if (VG=="") 
		{  
			if (VA.length==1)
			{
				if (VA[0]!=null) fil2="NH:"+VC+":"+VA[0];
			} else
			{              
				if (VA[0]!=null) if (VA[1]!=null) fil2="NRH:"+VC+":"+VA[0]+"~"+VA[1];
				if (VA[0]==null) if (VA[1]!=null) fil2="NRH:"+VC+":~"+VA[1];
				if (VA[0]!=null) if (VA[1]==null) fil2="NRH:"+VC+":"+VA[0]+"~";
			} 
		} else 
		{
			if (VA.length==1)
			{
				if (VA[0]!=null) fil2="NC:"+VG+":"+VC+":"+VA[0];
			} else
			{
				if (VA[0]!=null) if (VA[1]!=null) fil2="NRC:"+VG+":"+VC+":"+VA[0]+"~"+VA[1];
				if (VA[0]==null) if (VA[1]!=null) fil2="NRC:"+VG+":"+VC+":~"+VA[1];
				if (VA[0]!=null) if (VA[1]==null) fil2="NRC:"+VG+":"+VC+":"+VA[0]+"~";
			} 
		}
		break;                           

   		case 'TIME':
   		case 'TIME2':
	case 'DATE':
		if (VG=="") 
		{
			if (VA.length==1)
			{
				if (VA[0]!=null) fil2="DH:"+VC+":"+VA[0]+"000000~"+VA[0]+"235959";
			} else
			{
				if (VA[0]!=null) if (VA[1]!=null) fil2="DH:"+VC+":"+VA[0]+"000000~"+VA[1]+"235959";
				if (VA[0]==null) if (VA[1]!=null) fil2="DH:"+VC+":~"+VA[1]+"235959";
				if (VA[0]!=null) if (VA[1]==null) fil2="DH:"+VC+":"+VA[0]+"000000~";
			}
		} else 
		{	
			if (VA.length==1)
			{
				if (VA[0]!=null) fil2="DC:"+VG+":"+VC+":"+VA[0]+"000000~"+VA[0]+"235959";
			} else
			{
				if (VA[0]!=null) if (VA[1]!=null) fil2="DC:"+VG+":"+VC+":"+VA[0]+"000000~"+VA[1]+"235959";
				if (VA[0]==null) if (VA[1]!=null) fil2="DC:"+VG+":"+VC+":~"+VA[1]+"235959";
				if (VA[0]!=null) if (VA[1]==null) fil2="DC:"+VG+":"+VC+":"+VA[0]+"000000~";
			}    
		}
		break;          


	default:
		alert(objF.value+"="+objC.value);
		break;
}
} 


//alert(fil+" / "+fil2+" / "+PAV);

parent.RefreshList(obj.getAttribute("nmd-mode"), obj.getAttribute("nmd-wf"), fil, fil2, PAV);
}       

function eventKeyUp(eve)
{    
switch((eve.shiftKey?"SHIFT-":"")+(eve.ctrlKey?"CTRL-":"")+(eve.altKey?"ALT-":"")+eve.keyCode)
{
case "13":  
	RefreshList();
	break;
}
}     

function RefreshTitle(wf,mode,etty,crc)
{
if (g_CACHE[(wf+"-"+mode+"-"+etty).toUpperCase()])
{
g_WF   =wf;
g_MODE =mode;
g_ETTY =etty;         

document.body.innerHTML=g_CACHE[(wf+"-"+mode+"-"+etty).toUpperCase()];
RefreshList();
} else
{             

var obj2=document.getElementById("main");

obj=document.getElementById("loadhidden");            
obj.src="ReportViewer.aspx?ut="+g_UT+amp()+"file=NucleusWF.Base.Ejecucion.ConsolaTitulo.rpt"+amp()+"mode="+mode+amp()+"wf="+wf+amp()+"DEBUG="+g_DEBUG+amp()+"DEBUGETTY="+etty+amp()+"RELOAD=1"+amp()+"crc="+crc;
//falta pasar el crc
}
}     

function RefreshTable(wf,mode,etty,label,htmlbody)
{          
//guardo en CACHE
g_CACHE[(wf+"-"+mode+"-"+etty).toUpperCase()]=htmlbody;

g_WF   =wf;
g_MODE =mode;
g_ETTY =etty;
g_LABEL=label;                  

document.body.innerHTML=htmlbody;
parent.SetWindowTitle(null, g_LABEL);
RefreshList();
}

function OnLoad()
{              
obj=document.getElementById("main");
g_UT   =obj.getAttribute("nmd-ut");
g_WF   =obj.getAttribute("nmd-wf");
g_MODE =obj.getAttribute("nmd-mode");
g_DEBUG=obj.getAttribute("nmd-debug");
g_ETTY =obj.getAttribute("nmd-etty");
g_LABEL=g_MODE?obj.getAttribute("nmd-label"):"Tareas Pendientes";

if (obj.getAttribute("nmd-reload")=="1")
{
parent.RefreshTable(g_WF,g_MODE,g_ETTY,g_LABEL,document.body.innerHTML);
} else
{
parent.SetWindowTitle(window, g_LABEL);
RefreshList();
}
}
